import{_ as i,C as r,o as d,c as s,a3 as a,E as l}from"./chunks/framework.oxq6d-og.js";const h=JSON.parse('{"title":"NThread çağrı yaşam döngüsü","description":"","frontmatter":{},"headers":[],"relativePath":"nthread/call-lifecycle.md","filePath":"nthread/call-lifecycle.md"}'),t={name:"nthread/call-lifecycle.md"};function o(c,e,p,k,u,m){const n=r("NThreadSimulator");return d(),s("div",null,[e[0]||(e[0]=a('<h1 id="nthread-cagrı-yasam-dongusu" tabindex="-1">NThread çağrı yaşam döngüsü <a class="header-anchor" href="#nthread-cagrı-yasam-dongusu" aria-label="Permalink to &quot;NThread çağrı yaşam döngüsü&quot;">​</a></h1><p>Bir <code>NThread</code>, ömrü boyunca tam olarak bir OS thread&#39;ini yönlendirir. Varsayılan factory yolunda hangi thread&#39;in seçileceği <code>init()</code> sırasında belirlenir; <code>createAccessor()</code> ise bu işlemi bekleyip hazır accessor döndürür.</p><p>Aşağıdaki yavaşlatılmış modelde her clock darbesi bir instruction&#39;ı ilerletir. Disassembly penceresi bütün kodu aynı anda göstermek yerine <code>RIP</code>&#39;in geçtiği native kodu, farklı modüllerdeki stub konumlarını veya demo hedefini takip eder. Dokuz instruction grubu ve bellek adresleri öğretim için sabitlenmiştir; bunlar çalışan process&#39;ten okunmuş gerçek adresler değildir.</p>',3)),l(n,{locale:"tr"}),e[1]||(e[1]=a(`<div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>init: thread&#39;i suspend et → context&#39;i kaydet → spin&#39;e yönlendir → bir kez resume et</span></span>
<span class="line"><span>call: çalışan spin&#39;de getContext → hedef context&#39;i setContext → spin&#39;e dönüşü bekle</span></span>
<span class="line"><span>deinit: çalışan spin&#39;de savedContext&#39;i setContext → özgün RIP&#39;ten devam et → kaynakları kapat</span></span></code></pre></div><h2 id="baslatma-ve-iki-asamalı-donus-zinciri" tabindex="-1">Başlatma ve iki aşamalı dönüş zinciri <a class="header-anchor" href="#baslatma-ve-iki-asamalı-donus-zinciri" aria-label="Permalink to &quot;Başlatma ve iki aşamalı dönüş zinciri&quot;">​</a></h2><p>Başlatma, sistem modüllerindeki spin, <code>push reg; ret</code>, <code>jmp reg</code>, <code>ret</code> ve <code>add rsp, 0x28; ret</code> dizileri için yapılan taramanın tamamlanmasını bekler. Ardından thread bir kez suspend edilir, context&#39;i alınır, gerekli pivot stub&#39;ları seçilir ve bir kez resume edilerek spin stub&#39;daki <code>EB FE</code> döngüsünde çalışır durumda bırakılır. Bu aşama tamamlanmadan çağrı yapmaya çalışmak yerine factory&#39;nin resolve olmasını veya doğrudan oluşturulan accessor için <code>await init()</code> tamamlanmasını bekleyin.</p><p>Bu ilk inişteki bir <code>SuspendThread()</code> ve bir <code>ResumeThread()</code> dışında çağrı yolu thread&#39;in suspend count&#39;una dokunmaz. <code>EB FE</code>, register veya belleği değiştirmediği için NThread spin&#39;de çalışan thread&#39;in context&#39;ini güvenle okuyup değiştirebilir.</p><p>Kaydedilen snapshot yalnızca <code>RIP</code> ve <code>RSP</code> değildir: <code>INTEGER</code>, <code>CONTROL</code> ve <code>FLOATING_POINT</code> context grupları alınır; bunlar genel amaçlı register&#39;ları, control alanlarını ve XMM state&#39;ini kapsar. Simülatör okunabilirlik için <code>RIP</code>, <code>RSP</code>, <code>RAX</code>, <code>RBX</code>, <code>RBP</code>, <code>RCX</code>, <code>RDX</code>, <code>R8</code> ve <code>R9</code> alanlarını gösterir; simülatördeki NThread bu dokuz alanı yalnız <code>getContext()</code> ve <code>setContext()</code> üzerinden işler. Snapshot, deinit sonrasında thread&#39;i yakalandığı noktaya mümkün olduğunca yakın şekilde geri bırakmak içindir; hedefte o sırada tutulmuş lock&#39;ların semantiğini veya çağrıların bellek yan etkilerini geri sarmaz.</p><p><code>savedContext</code> init sırasında iki kez kopyalanır. İlk kopya, thread ilk kez suspend edildiğinde özgün <code>RIP</code> ve jump register değerini güvenceye alır. <code>jumpStub → spinStub</code> inişinden sonra spin döngüsünde çalışan live context yeniden clone edilir; ikinci kopyanın <code>RIP</code> ve seçilmiş jump register alanı ilk kopyadaki özgün değerlerle patch edilir. Böylece çalışma snapshot&#39;ı spin state&#39;ini temel alırken deinit thread&#39;i yakalandığı instruction&#39;a bırakabilir. Simülatörde <code>CONTEXT BUS</code> ve <code>0/2 → 2/2 KOPYA</code> göstergeleri tam bu akışı gösterir.</p><p>Çağrı alanı yakalanan stack&#39;in hemen altında değil, bir sayfa boşluk bırakılarak seçilir:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>stackBegin = align16(capturedRsp - 4096)</span></span>
<span class="line"><span>callRsp    = stackBegin - 136</span></span>
<span class="line"><span></span></span>
<span class="line"><span>örnek: capturedRsp = 0x000000A418F8C8C0</span></span>
<span class="line"><span>       stackBegin  = 0x000000A418F8B8C0</span></span>
<span class="line"><span>       callRsp     = 0x000000A418F8B838</span></span></code></pre></div><p>Bu 4096 byte&#39;lık pay, deinit sonrasında stack belleğinde kalabilen dispatch pointer&#39;larının normal call chain&#39;iyle erkenden çakışma riskini azaltır; stack belleği restore edilmez.</p><p>Thread spin döngüsüne ulaştıktan sonra NThread çağrı stack&#39;ini doğrudan soyut bir şema olarak varsaymaz; <code>push reg; ret</code> stub&#39;ını iki aşamada çalıştırarak zinciri stack üzerinde kurar ve spin noktasına geri döner:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Stage A: RSP = callRsp + 56</span></span>
<span class="line"><span>         push spinStub; ret</span></span>
<span class="line"><span>         → spinStub adresinin [callRsp + 48] slotuna yerleştiğini kurar</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Stage B: RSP = callRsp + 8</span></span>
<span class="line"><span>         push addRsp28RetStub; ret</span></span>
<span class="line"><span>         → ilk ret add rsp, 0x28; ret stub&#39;ına gider</span></span>
<span class="line"><span>         → ikinci ret [callRsp + 48]&#39;deki spinStub&#39;a gider</span></span></code></pre></div><p>Stage B&#39;deki iki <code>ret</code> arasında <code>add rsp, 0x28</code> çalışır. Bu iki dönüş sıçraması normal sıfır-stack-argümanlı çağrının dönüş yolunu daha kullanıcı çağrısı gönderilmeden yürütür: <code>callRsp</code>&#39;deki temizleyici, 32 byte shadow space ve spin dönüş noktası birlikte doğrulanmış olur. Bu, sonraki çağrılarda thread&#39;in hedef fonksiyondan aynı, bilinen çalışan spin state&#39;ine dönmesinin temelidir. Zincirin iki kere <code>ret</code> etmesi ve her iki seferde beklenen yere inmesi stabilite kontrolünün önemli parçasıdır; aşamalardan biri spin&#39;e dönmezse init başarısız olur.</p><h2 id="bir-cagrı" tabindex="-1">Bir çağrı <a class="header-anchor" href="#bir-cagrı" aria-label="Permalink to &quot;Bir çağrı&quot;">​</a></h2><p>NThread, thread <code>spinStub</code> üzerindeki <code>EB FE</code> döngüsünde çalışırken <code>getContext()</code> ile context&#39;i alır; parametreleri ve gerektiğinde stack slotlarını hazırlayıp <code>RIP</code>&#39;i hedef fonksiyona ayarlayarak <code>setContext()</code> uygular. Çağrı yolunda <code>SuspendThread()</code> veya <code>ResumeThread()</code> çalıştırılmaz. Hedef fonksiyon dönüşte <code>callRsp</code>&#39;deki <code>add rsp, 0x28; ret</code> zincirini izleyerek yeniden spin stub&#39;a gelir; poller <code>RIP == spinStub</code> durumunu görür ve sonucu context&#39;ten okur. Enabled thread çağrılar arasında native uygulama kodunda dolaşmaz, <code>EB FE</code> spin döngüsünde çalışmaya devam eder. Dörtten fazla parametre varsa çağrı için ek stack temizleme stub&#39;ı ayrılır; çağrı sonrasında temel dönüş zinciri geri yazılmaya çalışılır.</p><p>Async <code>call()</code> spin noktasını polling ile bekler. <code>callSync()</code> aynı işi JavaScript thread&#39;ini yield etmeden busy-spin ile yapar; uzun çağrıda host CPU&#39;sunu tüketir. Timeout, yalnızca fonksiyonun yavaş olduğunu değil, spin noktasına dönemediğini ifade eder.</p><h2 id="temizleme-ve-basarısızlık" tabindex="-1">Temizleme ve başarısızlık <a class="header-anchor" href="#temizleme-ve-basarısızlık" aria-label="Permalink to &quot;Temizleme ve başarısızlık&quot;">​</a></h2><p><code>deinit()</code> normal yaşam döngüsünün parçasıdır. Thread spin döngüsündeyken kaydedilen context&#39;i <code>setContext()</code> ile geri uygular; thread ek bir resume gerektirmeden özgün <code>RIP</code>&#39;ten devam eder. Ardından NThread&#39;in thread handle&#39;ı ve kullandığı geçici kaynaklar kapatılır. Her çağrı zincirini <code>try/finally</code> ile kurun.</p><p>Simülatörde <strong>Disable</strong>, otomatik demo çağrısı sürüyorsa onun spin&#39;e dönmesini bekleyip ardından <code>deinit()</code> gösterimini başlatır. Bu bir arayüz güvenlik sırasıdır; gerçek kodda lifecycle sahibinin <code>call()</code> ile <code>deinit()</code> işlemlerini birbiriyle yarıştırmaması gerekir.</p><p>Timeout veya thread ölümü sonrasında thread&#39;in hangi durumda kaldığı belirsiz olabilir. Aynı accessor üzerinde körlemesine yeni context yazmayın; hedef/thread durumunu inceleyin ve kontrollü testte yeni bir accessor ile yeniden başlayın.</p>`,19))])}const b=i(t,[["render",o]]);export{h as __pageData,b as default};
